import random

def simulate_haggle(list_price: float, cost: float, min_profit: float = 3.0) -> list[dict]:
    """Generate a haggle conversation. Returns SFT training pairs."""
    floor = cost + min_profit
    pairs = []

    # Customer opens below list
    offer = round(list_price * random.uniform(0.5, 0.85), 2)
    pairs.append({
        'prompt': f'I want to buy this. Can you do ${offer:.2f}?',
        'response': _seller_response(offer, list_price, floor)
    })

    # Second round if needed
    if offer < floor:
        offer2 = round(min(list_price, offer * random.uniform(1.05, 1.2)), 2)
        pairs.append({
            'prompt': f'Okay, what about ${offer2:.2f}?',
            'response': _seller_response(offer2, list_price, floor)
        })

    return pairs

def _seller_response(offer: float, list_price: float, floor: float) -> str:
    if offer >= list_price:
        return 'Absolutely, that works. Let me get that ready for you.'
    elif offer >= floor:
        return f'${offer:.2f} works for me. Deal.'
    elif offer >= floor - 0.50:
        return f'Closest I can go is ${floor:.2f} — that covers my costs with just enough margin.'
    else:
        return f'I appreciate the offer but I can\'t go below ${floor:.2f}. That\'s my hard floor.'
```

