import { useState } from 'react';

function ProductCard({ name, price, cost, onBuy }) {
    const [offer, setOffer] = useState('');
    const [message, setMessage] = useState('');
    const floor = cost + 3.0;

    const handleOffer = () => {
        const o = parseFloat(offer);
        if (isNaN(o)) return;
        if (o >= price) {
            setMessage('Deal! Processing at list price.');
            onBuy(price);
        } else if (o >= floor) {
            setMessage(`Deal at $${o.toFixed(2)}!`);
            onBuy(o);
        } else {
            setMessage(`Can't go below $${floor.toFixed(2)} — that's our floor.`);
        }
    };

    return (
        <div className="product-card">
            <h2>{name}</h2>
            <p>List price: <strong>${price.toFixed(2)}</strong></p>
            <button onClick={() => onBuy(price)}>Buy at ${price.toFixed(2)}</button>
            <div className="haggle">
                <input
                    type="number"
                    placeholder="Make an offer"
                    value={offer}
                    onChange={e => setOffer(e.target.value)}
                />
                <button onClick={handleOffer}>Submit Offer</button>
                {message && <p className="response">{message}</p>}
            </div>
        </div>
    );
}
