import stripe
import os

stripe.api_key = os.environ['STRIPE_SECRET_KEY']  # rk_test_... for sandbox

def charge_card(amount_cents: int, payment_method_id: str, description: str = '') -> dict:
    """Create a PaymentIntent and confirm it. amount_cents = 100 means $1.00."""
    try:
        intent = stripe.PaymentIntent.create(
            amount=amount_cents,
            currency='usd',
            payment_method=payment_method_id,
            confirm=True,
            description=description,
            automatic_payment_methods={'enabled': True, 'allow_redirects': 'never'},
        )
        return {'success': True, 'payment_intent_id': intent.id, 'status': intent.status}
    except stripe.error.CardError as e:
        return {'success': False, 'error': e.user_message, 'code': e.code}
    except stripe.error.StripeError as e:
        return {'success': False, 'error': str(e)}
